module RefModule(
    input wire clk,
    input wire rst,
    input wire send_data,
    input wire ack,
    output reg data_out,
    output reg ready
);
    reg [1:0] pipeline_reg;
    localparam IDLE = 2'b00,
               SEND = 2'b01,
               WAIT_ACK = 2'b10;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            pipeline_reg <= IDLE;
            data_out <= 0;
            ready <= 1;
        end else begin
            case (pipeline_reg)
                IDLE: begin
                    ready <= 1;
                    if (send_data) begin
                        pipeline_reg <= SEND;
                        data_out <= 1; // Indicate sending data
                    end
                end
                SEND: begin
                    ready <= 0;
                    if (ack) begin
                        pipeline_reg <= IDLE;
                        data_out <= 0; // Clear data indication
                    end
                end
                default: pipeline_reg <= IDLE;
            endcase
        end
    end
endmodule
